        staff.sort((a, b) -> {
            int deptCmp = a.dept.compareTo(b.dept);
            if (deptCmp != 0) return deptCmp;
            return Double.compare(b.salary, a.salary);  // salary desc
        });
        staff.forEach(e -> System.out.println(e));
    }
}

