import java.util.*;
class ComparatorFactory {
    static Comparator<String> byName() {
        return (a, b) -> a.compareTo(b);
    }
    static Comparator<String> byLength() {
        return (a, b) -> Integer.compare(a.length(), b.length());
    }
    static Comparator<String> byLengthDesc() {
        return (a, b) -> Integer.compare(b.length(), a.length());
    }
}
public class App {
    public static void main(String[] args) {
        List<String> names = Arrays.asList("Priya", "Raj", "Aisha");

        List<String> n1 = new ArrayList<>(names);
        n1.sort(ComparatorFactory.byName());
        System.out.println("By name: " + n1);

        List<String> n2 = new ArrayList<>(names);
        n2.sort(ComparatorFactory.byLength());
        System.out.println("By length: " + n2);

        List<String> n3 = new ArrayList<>(names);
        n3.sort(ComparatorFactory.byLengthDesc());
        System.out.println("By length desc: " + n3);
    }
}

import java.util.*;
@FunctionalInterface
interface Transformer<T> {
    T transform(T input);
}
public class App {
    static <T> List<T> applyAll(List<T> list, Transformer<T> t) {
        List<T> result = new ArrayList<>();
        for (T item : list) result.add(t.transform(item));
        return result;
    }
    public static void main(String[] args) {
        List<String> names = Arrays.asList("Aisha", "Raj", "Priya");
        System.out.println(applyAll(names, s -> s.toUpperCase()));

        List<Integer> nums = Arrays.asList(5, 10, 15);
        System.out.println(applyAll(nums, n -> n * 2));
    }
}

import java.util.*;
class Product {
    String name; double price;
    Product(String n, double p) { name=n; price=p; }
    public String getName() { return name; }
    public double getPrice() { return price; }
    public String toString() { return name; }
}
public class App {
    public static void main(String[] args) {
        List<Product> products = new ArrayList<>(Arrays.asList(
            new Product("Mouse",    719),
            new Product("Keyboard", 1599),
            new Product("Java Book", 552),
            new Product("USB Hub",   374)
        ));

        List<Product> byName = new ArrayList<>(products);
        byName.sort(Comparator.comparing(p -> p.getName()));
        System.out.println("By name: " + byName);

        List<Product> byPrice = new ArrayList<>(products);
        byPrice.sort(Comparator.comparingDouble(p -> p.getPrice()));
        System.out.println("By price: " + byPrice);

        List<Product> byLen = new ArrayList<>(products);
        byLen.sort(Comparator.comparingInt(p -> p.getName().length()));
        System.out.println("By name length: " + byLen);
    }
}

import java.util.*;
class Student {
    String name; double gpa;
    Student(String n, double g) { name=n; gpa=g; }
}
public class App {
    public static void main(String[] args) {
        List<Student> students = Arrays.asList(
            new Student("Aisha",  3.9),
            new Student("Raj",    3.2),
            new Student("Priya",  3.8),
            new Student("Vikram", 3.6),
            new Student("Anita",  3.1)
        );

        // Step 1: filter (removeIf with lambda)
        List<Student> filtered = new ArrayList<>(students);
        filtered.removeIf(s -> s.gpa < 3.5);

        // Step 2: sort (lambda comparator)
        filtered.sort((a, b) -> Double.compare(b.gpa, a.gpa));

        // Step 3: print top 3
        int limit = Math.min(3, filtered.size());
        for (int i = 0; i < limit; i++) {
            Student s = filtered.get(i);
            System.out.println("#" + (i+1) + " " + s.name + ": " + s.gpa);
        }
    }
}

import java.util.*;
class Product {
    String name, category;
    double price;
    int stock;
    Product(String n, String c, double p, int s) { name=n; category=c; price=p; stock=s; }
    public String toString() { return String.format("  %s ₹%.0f (stock=%d)", name, price, stock); }
}
public class App {
    public static void main(String[] args) {
        List<Product> catalog = new ArrayList<>(Arrays.asList(
            new Product("Mouse",           "Electronics", 799,   45),
            new Product("Keyboard",        "Electronics", 1999,   8),
            new Product("Monitor",         "Electronics", 18999,  0),  // out of stock
            new Product("Java Programming","Books",        649,   20),
            new Product("USB Hub",         "Electronics",  499,  60)
        ));

        // Group by category
        Map<String, List<Product>> byCategory = new LinkedHashMap<>();
        catalog.forEach(p -> byCategory.computeIfAbsent(p.category, k -> new ArrayList<>()).add(p));

        // Print each category sorted by price
        List<String> cats = new ArrayList<>(byCategory.keySet());
        Collections.sort(cats);
        cats.forEach(cat -> {
            System.out.println(cat + ":");
            List<Product> catProducts = byCategory.get(cat);
            catProducts.sort((a, b) -> Double.compare(a.price, b.price));
            catProducts.forEach(p -> System.out.println(p));
        });

        // Most expensive (all, including out of stock)
        List<Product> sorted = new ArrayList<>(catalog);
        sorted.sort((a, b) -> Double.compare(b.price, a.price));
        System.out.println("Most expensive: " + sorted.get(0).name + " ₹" + (int)sorted.get(0).price);

        // Remove out of stock
        catalog.removeIf(p -> p.stock == 0);
        System.out.println("After removing out-of-stock (Monitor): " + catalog.size() + " products remain");
    }
}
